    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        def dfs(groups):
            if not nums:
                return True
            v = nums.pop()
            for i, group in enumerate(groups):
                if group + v <= target:
                    groups[i] += v
                    if dfs(groups):
                        return True
                    groups[i] -= v
                if not group:
                    break
            nums.append(v)
            return False

        nums.sort()
        if sum(nums) % k:
            return False
        target = sum(nums) // k
        if nums[-1] > target:
            return False
        while nums and nums[-1] == target:
            nums.pop()
            k -= 1
        return dfs([0] * k)
